import { Check, X, Scissors } from "lucide-react";
import { SERVICES } from "../constants";

export default function FormPanel({ form, setForm, editing, onSubmit, onCancel }) {
  const handleChange = (field) => (e) =>
    setForm((prev) => ({ ...prev, [field]: e.target.value }));

  return (
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '80vh',
      padding: '20px'
    }}>

      <aside className="pb-sidebar" style={{
        width: '100%',
        maxWidth: '400px',
        position: 'relative',
        zIndex: 5,
        padding: '40px',
        borderRadius: '0',
        boxShadow: '0 20px 50px rgba(0,0,0,0.5)',

        /* AJUSTE DE OPACIDADE: Mudamos de 0.85/0.9 para 0.7 para ficar mais claro */
        backgroundImage: 'linear-gradient(rgba(0, 0, 0, 0.7), rgba(0, 0, 0, 0.7)), url("https://images.unsplash.com/photo-1599351431613-18ef1fdd27e1?q=80&w=688&auto=format&fit=crop")',
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        border: '1px solid var(--amarelo)',
        color: 'white' // Garante que os textos fiquem legíveis sobre o fundo escuro
      }}>

        <p className="pb-section-label" style={{ 
          justifyContent: 'center', 
          marginBottom: '20px', 
          color: 'var(--amarelo)',
          borderColor: 'var(--amarelo)' 
        }}>
          <Scissors size={14} style={{ marginRight: '8px' }} />
          Sistema de Agendamento
        </p>

        <h2 className="pb-form-title" style={{ 
          textAlign: 'center', 
          fontSize: '24px', 
          marginBottom: '30px', 
          color: 'white' 
        }}>
          {editing ? "Editar Registro" : "Faça seu Agendamento"}
        </h2>

        <div className="pb-field" style={{ marginBottom: '20px' }}>
          <label className="pb-label" style={{ color: 'var(--amarelo)' }}>Nome Completo</label>
          <input
            className="pb-input"
            placeholder="Seu nome aqui"
            value={form.name}
            onChange={handleChange("name")}
            style={{ 
              background: 'rgba(255, 255, 255, 0.1)', 
              color: 'white', 
              border: '1px solid rgba(255, 255, 255, 0.2)' 
            }}
          />
        </div>

        <div className="pb-field" style={{ marginBottom: '20px' }}>
          <label className="pb-label" style={{ color: 'var(--amarelo)' }}>Serviço Desejado</label>
          <select
            className="pb-select"
            value={form.service}
            onChange={handleChange("service")}
            style={{ 
              background: 'rgba(255, 255, 255, 0.1)', 
              color: 'white', 
              border: '1px solid rgba(255, 255, 255, 0.2)' 
            }}
          >
            <option value="" style={{ background: '#222' }}>Selecione um serviço</option>
            {SERVICES.map((s) => (
              <option key={s} value={s} style={{ background: '#222' }}>{s}</option>
            ))}
          </select>
        </div>

        <div className="pb-field" style={{ marginBottom: '30px' }}>
          <label className="pb-label" style={{ color: 'var(--amarelo)' }}>Data &amp; Hora</label>
          <div className="pb-date-row" style={{ display: 'flex', gap: '10px' }}>
            <input
              className="pb-input"
              type="date"
              value={form.date}
              onChange={handleChange("date")}
              style={{ background: 'rgba(255, 255, 255, 0.1)', color: 'white', border: '1px solid rgba(255, 255, 255, 0.2)' }}
            />
            <input
              className="pb-input"
              type="time"
              value={form.time}
              onChange={handleChange("time")}
              style={{ background: 'rgba(255, 255, 255, 0.1)', color: 'white', border: '1px solid rgba(255, 255, 255, 0.2)' }}
            />
          </div>
        </div>

        <button
          className={`pb-btn-primary${editing ? " edit" : ""}`}
          onClick={onSubmit}
          style={{ 
            width: '100%', 
            padding: '15px', 
            fontWeight: 'bold', 
            background: 'var(--amarelo)', 
            color: 'var(--preto)',
            border: 'none',
            cursor: 'pointer'
          }}
        >
          {editing ? "SALVAR ALTERAÇÕES" : "CONFIRMAR AGENDAMENTO"}
        </button>

        {editing && (
          <button 
            className="pb-btn-cancel" 
            onClick={onCancel}
            style={{ width: '100%', marginTop: '15px', background: 'transparent', border: 'none', color: 'rgba(255,255,255,0.6)', cursor: 'pointer' }}
          >
            <X size={11} /> Cancelar edição
          </button>
        )}
      </aside>
    </div>
  );
}
